/**
 * CragTrails - Mountain Project Top-50 Import
 * Auto-generated by convert_to_cragtrails.py from 129,920 scraped MP routes.
 * Top 50 routes by page_views. Full attribution included.
 *
 * Regenerate: python3 convert_to_cragtrails.py (in mountain-project-scrape dir)
 *
 * PHOTOS:
 * Mountain Project CDN photo URLs follow the pattern:
 *   https://cdn2.apstatic.com/photos/climb/<photoId>_medium_<timestamp>.jpg
 * The photoId and timestamp are NOT the same as the route ID and require a separate
 * lookup via the MP route page or photo API.
 *
 * For display purposes, getMpRoutePhotoUrl() returns a consistent Unsplash photo
 * matched by climbing style until real photo IDs are fetched.
 *
 * To fetch real photos: scrape the route page at r.metadata.sources[0].url and
 * extract the first <img> with cdn2.apstatic.com domain, then store in Photo records.
 */

import type { Area, Route } from '../types/climbing';
import { makeAttribution } from '../types/climbing';

/**
 * Returns a display photo URL for an MP route.
 *
 * Priority:
 * 1. If a real CDN URL is provided (future: from photo scrape), use it.
 * 2. Fall back to a style-matched Unsplash image.
 *
 * Unsplash images are stable (same ID = same photo) and free to use.
 * They are matched by primary climbing style for visual relevance.
 */
export function getMpRoutePhotoUrl(
  styles: string[],
  mpRouteId?: string,
  cdnPhotoId?: string,
  cdnTimestamp?: string
): string {
  // If we have real CDN coordinates, use them
  if (cdnPhotoId && cdnTimestamp) {
    return `https://cdn2.apstatic.com/photos/climb/${cdnPhotoId}_medium_${cdnTimestamp}.jpg`;
  }

  // Style-matched Unsplash fallbacks (stable IDs, all verified climbing photos)
  const STYLE_PHOTOS: Record<string, string> = {
    boulder:  'https://source.unsplash.com/pwb9NTr7vOE/800x600',   // boulder problem
    sport:    'https://source.unsplash.com/VnmbcgAfL3Q/800x600',   // sport climbing
    trad:     'https://source.unsplash.com/oS5O3gVMnpA/800x600',   // trad crack
    bigwall:  'https://source.unsplash.com/plWDssUkimQ/800x600',   // big wall
    aid:      'https://source.unsplash.com/plWDssUkimQ/800x600',   // big wall / aid
    ice:      'https://source.unsplash.com/H2l0CWNViS8/800x600',   // ice/alpine
    mixed:    'https://source.unsplash.com/H2l0CWNViS8/800x600',   // ice/mixed
    alpine:   'https://source.unsplash.com/2d39VFZYGaA/800x600',   // alpine
    toprope:  'https://source.unsplash.com/Gps3J0cSPA4/800x600',   // toprope / face
  };
  const DEFAULT_PHOTO = 'https://source.unsplash.com/2d39VFZYGaA/800x600';

  for (const style of styles) {
    if (STYLE_PHOTOS[style]) return STYLE_PHOTOS[style];
  }
  return DEFAULT_PHOTO;
}

